import{_ as s,o as e,c as i,ae as t}from"./chunks/framework.D6sYw4vw.js";const g=JSON.parse('{"title":"准备go-zero环境","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/04-go-zero环境准备.md","filePath":"tutorial/04-go-zero环境准备.md","lastUpdated":1773144464000}'),a={name:"tutorial/04-go-zero环境准备.md"};function l(p,o,n,d,c,r){return e(),i("div",null,[...o[0]||(o[0]=[t('<h1 id="准备go-zero环境" tabindex="-1">准备go-zero环境 <a class="header-anchor" href="#准备go-zero环境" aria-label="Permalink to &quot;准备go-zero环境&quot;">​</a></h1><h2 id="go-zero介绍" tabindex="-1">go-zero介绍 <a class="header-anchor" href="#go-zero介绍" aria-label="Permalink to &quot;go-zero介绍&quot;">​</a></h2><p><code>go-zero</code> 是一个专注于微服务的 Go 语言框架，旨在通过其丰富的功能和工具集使开发、部署和维护微服务变得更加简单和高效。以下是关于 <code>go-zero</code> 的一些核心特点和功能简介：</p><ol><li><p><strong>简洁的 API 设计</strong>：<code>go-zero</code> 提供了一套简单且高效的 API 设计工具，使得开发者可以更快地创建和维护 API 端点。</p></li><li><p><strong>强大的并发模型</strong>：框架采用了类似于 Erlang 的并发模型，结合了 Go 语言原生的 goroutine，以实现高效、可靠的并发处理。</p></li><li><p><strong>内置中间件支持</strong>：<code>go-zero</code> 附带了多种常用的中间件，如限流、缓存、鉴权等，以便更容易地构建安全、高效的微服务。</p></li><li><p><strong>自动生成代码</strong>：通过 <code>goctl</code> 工具，开发者可以自动生成大量代码，包括 API 定义、数据模型等，大大加速了开发速度。</p></li><li><p><strong>弹性设计</strong>：框架内置了故障恢复、熔断、负载均衡等机制，帮助开发者构建更加弹性和稳定的系统。</p></li><li><p><strong>高性能</strong>：通过其优化的并发模型和内置功能（如缓存），<code>go-zero</code> 旨在提供高性能的微服务。</p></li><li><p><strong>易于集成</strong>：它可以与其他 Go 语言库和框架轻松集成，提供了很大的灵活性。</p></li></ol><p>总之，<code>go-zero</code> 是一个高效、灵活的微服务框架，它为 Go 语言的开发者提供了一个简单且功能强大的工具集，使得微服务的开发、部署和维护变得更加简单和高效。</p><h2 id="goctl安装" tabindex="-1">goctl安装 <a class="header-anchor" href="#goctl安装" aria-label="Permalink to &quot;goctl安装&quot;">​</a></h2><p><code>go-zero</code> 是一个用于构建微服务的框架，而 <code>goctl</code> 是 <code>go-zero</code> 的命令行工具，用于生成、管理和维护 <code>go-zero</code> 项目。以下是为 <code>go-zero</code> 准备环境并安装 <code>goctl</code> 的步骤：</p><ol><li><p><strong>安装 Go</strong><br> 在使用 <code>go-zero</code> 之前，你首先需要确保已经正确安装了 Go 语言。你可以访问 <a href="https://golang.org/dl/" target="_blank" rel="noreferrer">Go 的官方下载页面</a> 获取适合你操作系统的安装包。</p></li><li><p><strong>配置 Go 环境变量</strong><br> 确保你的 <code>GOPATH</code> 和 <code>GOBIN</code> 环境变量已经正确设置，并且 <code>$GOBIN</code> 或 <code>$GOPATH/bin</code> 在你的 <code>PATH</code> 中。这样，当你安装 Go 工具或库时，你可以在任何地方从命令行运行它们。</p><ul><li><p>设置 <code>GOPATH</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GOPATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME/go</span></span></code></pre></div></li><li><p>设置 <code>GOBIN</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GOBIN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$GOPATH/bin</span></span></code></pre></div></li><li><p>把 <code>GOBIN</code> 添加到 <code>PATH</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PATH:$GOBIN</span></span></code></pre></div></li></ul><p>注意: 上述命令是针对 Unix-like 系统的 (如 Linux 或 MacOS)。如果你使用的是 Windows，你需要修改系统环境变量。</p></li><li><p><strong>安装 goctl</strong><br> 使用 <code>go get</code> 命令，你可以轻松安装 <code>goctl</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">GO111MODULE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">on</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> go</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> github.com/zeromicro/go-zero/tools/goctl@latest</span></span></code></pre></div></li><li><p><strong>验证安装</strong><br> 通过运行以下命令验证 <code>goctl</code> 是否已正确安装：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">goctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span></span></code></pre></div><p>如果安装成功，它应该会显示 <code>goctl</code> 的当前版本号。</p></li><li><p><strong>开始使用 goctl</strong><br> 有了 <code>goctl</code>，你现在可以开始创建、管理和维护 <code>go-zero</code> 项目了。为了更深入地了解如何使用这个工具，你可以运行 <code>goctl help</code> 以获取相关命令和说明。</p></li></ol><p>按照上述步骤，你应该能够成功设置 <code>go-zero</code> 环境并安装 <code>goctl</code> 工具。</p><h2 id="protoc的安装" tabindex="-1">protoc的安装 <a class="header-anchor" href="#protoc的安装" aria-label="Permalink to &quot;protoc的安装&quot;">​</a></h2><p>protoc 是一个用于生成代码的工具，它可以根据 proto 文件生成C++、Java、Python、Go、PHP 等多重语言的代码，而 gRPC 的代码生成还依赖 protoc-gen-go，protoc-gen-go-grpc 插件来配合生成 Go 语言的 gRPC 代码。</p><p>通过 goctl 可以一键安装 protoc，protoc-gen-go，protoc-gen-go-grpc 相关组件，你可以执行如下命令：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> goctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force</span></span></code></pre></div><p>安装完毕后，你可以执行如下指令来验证是否安装成功：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> goctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span></span></code></pre></div><h2 id="goctl-vscode插件的安装" tabindex="-1">goctl-vscode插件的安装 <a class="header-anchor" href="#goctl-vscode插件的安装" aria-label="Permalink to &quot;goctl-vscode插件的安装&quot;">​</a></h2><p>在 Visual Studio Code (VSCode) 中，有一个扩展市场，使你可以搜索并安装各种插件来增强编辑器的功能。以下是在 VSCode 中安装 <code>goctl</code> 插件的步骤：</p><ol><li><p><strong>启动 VSCode</strong><br> 如果还没有启动 VSCode，首先启动它。</p></li><li><p><strong>进入扩展市场</strong><br> 在左侧边栏上，点击四个方块形成的图标（或按 <code>Ctrl+Shift+X</code>）进入扩展市场。</p></li><li><p><strong>搜索插件</strong><br> 在扩展市场的搜索框中输入 <code>goctl</code>。</p></li><li><p><strong>安装插件</strong><br> 在搜索结果中找到 <code>goctl</code> 插件。点击安装按钮来安装它。</p></li><li><p><strong>重新加载VSCode</strong><br> 安装完插件后，可能需要重新加载 VSCode 以确保插件能够正常工作。有些插件在安装时会提示你重新加载，但并不是所有的都需要。</p></li><li><p><strong>配置 (如有必要)</strong><br> 根据你的需要，进入 VSCode 的设置，定制 <code>goctl</code> 插件的配置。</p></li></ol><p>现在，你应该在 VSCode 中成功安装了 <code>goctl</code> 插件，并可以开始使用其功能了。</p><p><strong>注意</strong>：随着时间的推移，VSCode 或插件的具体细节可能会发生变化。如果上述步骤在未来变得不准确，建议参考 VSCode 和 <code>goctl</code> 插件的官方文档。</p>',20)])])}const k=s(a,[["render",l]]);export{g as __pageData,k as default};
